type WeatherMode = "sunny" | "windy" | "stormy";

const currentMode = ref<WeatherMode>("sunny");

const toggleMode = () => {
  const modes: WeatherMode[] = ["sunny", "windy", "stormy"];
  const currentIndex = modes.indexOf(currentMode.value);
  currentMode.value = modes[(currentIndex + 1) % modes.length];
};
