<style scoped>
.weather-widget {
  background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
  padding: 2rem;
  border-radius: 2rem;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  cursor: pointer;
  transition: transform 0.3s ease;
  user-select: none;
  max-width: 350px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  text-align: center;
}

.weather-widget:hover {
  transform: translateY(-5px);
}

.weather-container {
  width: 250px;
  height: 250px;
  margin: 0 auto;
}

.weather-svg {
  width: 100%;
  height: 100%;
}

.sun-group {
  transform-origin: center;
  transition:
    opacity 0.8s ease-in-out,
    transform 0.8s ease-in-out;
}

.mode-stormy .sun-group {
  opacity: 0;
  transform: scale(0.8);
  pointer-events: none;
}

/* Sun Rays: Drawing effect */
.sun-rays {
  fill: #f8ffa1;
  stroke: #ffffff;
  stroke-width: 1;
  stroke-dasharray: 2000;
  stroke-dashoffset: 2000;
  animation: draw-rays 3s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes draw-rays {
  to {
    stroke-dashoffset: 0;
  }
}

.sun-core {
  fill: #ffd34f;
  stroke: #ffffff;
  stroke-width: 0.5;
  animation: pulse 4s ease-in-out infinite;
  transform-origin: center;
}

@keyframes pulse {
  0%,
  100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.08);
  }
}

/* Clouds: Parallax Floating effect */
.cloud {
  transition:
    fill 0.8s ease,
    transform 0.8s ease,
    opacity 0.8s ease;
  opacity: 0;
  pointer-events: none;
}

.mode-windy .cloud,
.mode-stormy .cloud {
  opacity: 1;
  pointer-events: auto;
}

.cloud-back {
  fill: #94a3b8;
  animation: float-back 6s ease-in-out infinite alternate;
}

.cloud-front {
  fill: #f8fafc;
  animation: float-front 4s ease-in-out infinite alternate;
}

.mode-stormy .cloud-back {
  fill: #475569;
}

.mode-stormy .cloud-front {
  fill: #64748b;
}

@keyframes float-back {
  from {
    transform: translateX(-8px) translateY(-2px);
  }
  to {
    transform: translateX(8px) translateY(2px);
  }
}

@keyframes float-front {
  from {
    transform: translateX(-20px) translateY(5px);
  }
  to {
    transform: translateX(20px) translateY(-5px);
  }
}

/* States */
.agitated {
  animation-duration: 1.2s !important;
}

.mode-stormy .agitated {
  animation-duration: 0.8s !important;
}

.weather-info {
  margin-top: 1.5rem;
  color: white;
}

.mode-badge {
  display: inline-block;
  padding: 0.5rem 1.5rem;
  border-radius: 1rem;
  font-weight: 800;
  letter-spacing: 0.05rem;
  transition: all 0.5s ease;
  margin-bottom: 0.5rem;
}

.mode-badge.sunny {
  background: #ffd34f;
  color: #000;
  box-shadow: 0 0 20px #ffd34f66;
}
.mode-badge.windy {
  background: #94a3b8;
  color: #fff;
  box-shadow: 0 0 20px #94a3b866;
}
.mode-badge.stormy {
  background: #475569;
  color: #fff;
  box-shadow: 0 0 20px #47556966;
}

.weather-info h3 {
